parameters.jsCode:
const aiRaw = $input.first().json;
const trigger = $('Trigger').first().json;

const recordId = trigger.contentId || trigger.id || '';
const handleIg = trigger.brand?.handle_ig || 'marca';

try {
  const content = aiRaw.choices?.[0]?.message?.content || '{}';
  const parsed = JSON.parse(content);
  const slides = parsed.slides || [];

  return slides.map(slide => ({
    json: {
      recordId,
      tenantId: trigger.tenantId || null,
      slide_number: slide.slide_number,
      title: slide.title || '',
      body_text: slide.body_text || '',
      footer: slide.footer || `@${handleIg}`,
      image_prompt: slide.image_prompt || '',
    }
  }));
} catch (e) {
  return [{ json: { recordId, error: 'Failed to parse: ' + e.message } }];
}

// Extraer id de la escena recién creada (Supabase devuelve array)
const raw = $input.first().json;
const scene = Array.isArray(raw) ? raw[0] : raw;
const slideData = $('Loop slides').first().json;
return [{ json: { ...slideData, sceneId: scene.id } }];

const input = $input.first().json;
const sceneData = $('Extraer ID escena').first().json;
const escenaId = sceneData.sceneId;
const slideData = sceneData;

const isWaitCallback = !!(input.body && typeof input.body === 'object' && input.body.code !== undefined);
const callback = isWaitCallback ? input.body : input;

const apiCode = callback.code;
const apiMsg = callback.msg || '';
const failMsg = (callback.data?.failMsg || '');

let imageRetryCount = 0;
try {
  const prev = $('Procesar resultado').first().json;
  if (prev.retryable) { imageRetryCount = prev.imageRetryCount || 0; }
} catch (e) {}

if (apiCode !== undefined && apiCode !== 200) {
  const retryableCodes = [500, 501, 502, 503];
  const retryableMessages = ['internal error', 'try again', 'server busy', 'temporarily unavailable'];
  const isRetryable = retryableCodes.includes(apiCode) || retryableMessages.some(m => (apiMsg + ' ' + failMsg).toLowerCase().includes(m));
  if (isRetryable && imageRetryCount < 3) {
    return [{ json: { escenaId, imageUrl: '', estado: 'Reintentando', errorMsg: 'Retry ' + (imageRetryCount + 1) + '/3: code=' + apiCode + ' ' + apiMsg, slide_number: slideData.slide_number, fatalError: false, retryable: true, imageRetryCount: imageRetryCount + 1, recordId: slideData.recordId, tenantId: slideData.tenantId } }];
  }
  return [{ json: { escenaId, imageUrl: '', estado: 'Error', errorMsg: 'Kie.ai code=' + apiCode + ': ' + apiMsg, slide_number: slideData.slide_number, fatalError: true, retryable: false, recordId: slideData.recordId, tenantId: slideData.tenantId } }];
}

if (!callback.data || !callback.data.resultJson) {
  return [{ json: { escenaId, imageUrl: '', estado: 'Error', errorMsg: isWaitCallback ? 'Callback de Kie.ai sin resultJson' : 'Timeout esperando callback de Kie.ai', slide_number: slideData.slide_number, fatalError: true, recordId: slideData.recordId, tenantId: slideData.tenantId } }];
}

let imageUrl = '';
let estado = 'Listo';
let errorMsg = '';
try {
  const resultJson = JSON.parse(callback.data.resultJson);
  imageUrl = resultJson.resultUrls?.[0] || '';
} catch (e) {
  estado = 'Error';
  errorMsg = 'Failed to parse result: ' + e.message;
}

if (!imageUrl && estado !== 'Error') {
  estado = 'Error';
  errorMsg = 'No image URL in response';
}

return [{ json: { escenaId, imageUrl, estado, errorMsg, slide_number: slideData.slide_number, fatalError: estado === 'Error', retryable: false, recordId: slideData.recordId, tenantId: slideData.tenantId } }];

const trigger = $('Trigger').first().json;
const recordId = trigger.contentId || trigger.id || '';
return [{ json: { recordId, tenantId: trigger.tenantId || null } }];

// En Dopla no hay tabla de modelos en Supabase todavía.
// Usar configuración hardcoded del modelo Kie.ai Nano Banana Pro.
const endpoint = 'https://api.kie.ai/api/v1/jobs/createTask';
const bodyTemplate = JSON.stringify({
  type: 'img2img',
  model: 'nano-banana-pro',
  prompt: '{prompt}',
  aspect_ratio: '{aspect_ratio}',
  callback_url: '{callback_url}'
});
return [{ json: { endpoint, bodyTemplate } }];

const modelo = $('Fetch modelo imagen').first().json;
const bodyTemplate = modelo['bodyTemplate'] || '';
const endpoint = modelo.endpoint || 'https://api.kie.ai/api/v1/jobs/createTask';
const prompt = $('Loop slides').first().json.image_prompt || '';
const aspectRatio = '1:1';

const escapedPrompt = JSON.stringify(prompt).slice(1, -1);
const body = bodyTemplate
  .replace(/\{prompt\}/g, escapedPrompt)
  .replace(/\{aspect_ratio\}/g, aspectRatio);

return [{ json: { endpoint, bodyWithCallback: body } }];

const original = $('Procesar resultado').first().json;
const wm = $input.first().json;
const imageUrl = (wm.success && wm.url) ? wm.url : (original.imageUrl || '');
return [{ json: {
  escenaId: original.escenaId,
  imageUrl,
  estado: original.estado,
  errorMsg: original.errorMsg || '',
  slide_number: original.slide_number,
  fatalError: original.fatalError || false,
  recordId: original.recordId,
  tenantId: original.tenantId
} }];

const brand = $('Trigger').first().json.brand || {};
const style = $('Trigger').first().json.style_prompts || {};
const trigger = $('Trigger').first().json;

let systemPrompt = style.prompt_sistema || '';
systemPrompt = systemPrompt
  .replace(/{brand_name}/g, brand.nombre || '')
  .replace(/{handle_ig}/g, brand.handle_ig || '')
  .replace(/{tono}/g, brand.tono || '')
  .replace(/{audiencia}/g, brand.audiencia || '')
  .replace(/{colores}/g, brand.colores || '')
  .replace(/{estilo_visual}/g, brand.estilo_visual || '')
  .replace(/{reglas_lenguaje}/g, brand.reglas_lenguaje || '');

if (!systemPrompt) {
  systemPrompt = `Eres un Art Director especializado en carruseles de Instagram para ${brand.nombre || 'la marca'}. Colores: ${brand.colores}. Estilo: ${brand.estilo_visual}. IDIOMA: textos en ESPANOL, image_prompt en ingles. SIEMPRE responde en JSON valido.`;
}

const numSlides = String(trigger.num_slides || 5);

let userPrompt = style.prompt_usuario || '';
userPrompt = userPrompt
  .replace(/{mi_hook}/g, trigger.mi_hook || '')
  .replace(/{mi_caption}/g, trigger.mi_caption || '')
  .replace(/{analisis}/g, trigger.analisis || '')
  .replace(/{hook_original}/g, trigger.hook_original || '')
  .replace(/{num_slides}/g, numSlides)
  .replace(/{brand_name}/g, brand.nombre || '')
  .replace(/{handle_ig}/g, brand.handle_ig || '')
  .replace(/{colores}/g, brand.colores || '');

if (!userPrompt) {
  userPrompt = `Genera un carrusel de ${numSlides} slides.\nHOOK: ${trigger.mi_hook || ''}\nCAPTION: ${trigger.mi_caption || ''}\nTEMA: ${trigger.hook_original || ''}\nCONTEXTO: ${trigger.analisis || ''}\n\nJSON con slides[] incluyendo title, body_text, footer, image_prompt.`;
}

return [{ json: { ...trigger, systemPrompt, userPrompt } }];
